import{_ as t,o as e,c as o,ag as i}from"./chunks/framework.BuUvxvtQ.js";const l="/assets/vesc.BrMYw7E9.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Other/VESC.md","filePath":"Other/VESC.md","lastUpdated":1775898880000}'),n={name:"Other/VESC.md"};function s(a,r,g,c,d,p){return e(),o("div",null,[...r[0]||(r[0]=[i('<h2 id="vesc上位机使用" tabindex="-1">VESC上位机使用 <a class="header-anchor" href="#vesc上位机使用" aria-label="Permalink to &quot;VESC上位机使用&quot;">​</a></h2><p>上位机需要和VESC固件相对应，建议是最新的固件搭配最新的上位机，截至目前（25/9/21）最新的上位机版本是6.06已在实验室仓库同步。</p><p><img src="'+l+'" alt="vesc"></p><p><a href="https://zhuanlan.zhihu.com/p/1910085988224574682" target="_blank" rel="noreferrer">校准参考</a></p><h2 id="vesc项目源码" tabindex="-1">VESC项目源码 <a class="header-anchor" href="#vesc项目源码" aria-label="Permalink to &quot;VESC项目源码&quot;">​</a></h2><p>前言：VESC固件源码建议在Linux环境下进行编译（在Windows环境中编译makefile有各种各样的语法问题），也可以在[在线编译](<a href="https://oshwhub.com/article/environment-free-build-up-everbamboovesc-edc-firmware-online-compilation-guide" target="_blank" rel="noreferrer">免环境搭建！everbamboo VESC电调固件在线编译指南 - 嘉立创EDA开源硬件平台</a>)不用搭建环境。</p><p>目录详细分析：<a href="https://xtzhyhydwl.github.io/2025/05/14/VESC%E4%BB%A3%E7%A0%81%E5%88%86%E6%9E%901%EF%BC%9A%E5%9B%BA%E4%BB%B6%E6%96%87%E4%BB%B6%E6%80%BB%E8%A7%88/" target="_blank" rel="noreferrer">VESC代码分析</a></p><p>代码分析视频： <a href="https://www.bilibili.com/video/BV1DZ42127Yk/?spm_id_from=333.1387.upload.video_card.click" target="_blank" rel="noreferrer">b站代码分析</a></p><p>项目地址：[bldc](<a href="https://github.com/vedderb/bldc/?tab=readme-ov-file" target="_blank" rel="noreferrer">vedderb/bldc：VESC 电机控制固件</a>)</p><p>项目目录：</p><ul><li><strong>applications/</strong>：上层“应用”任务（PPM/ADC 油门、UART/CAN 控制、自定义 APP）。想加自己的业务逻辑，就在这写。</li><li><strong>blackmagic/</strong>：用 Black Magic Probe 调试/下载相关脚本与规则。</li><li><strong>build/</strong>：编译生成的文件都在这里。</li><li><strong>ChibiOS_3.0.5/</strong>：RTOS 与 HAL（STM32 外设驱动、线程调度等）的完整源码。</li><li><strong>comm/</strong>：通讯协议与打包层（USB/串口/CAN、VESC 协议、指令解析）。</li><li><strong>documentation/</strong>：文档与示例。</li><li><strong>downloads/</strong>：第三方依赖的下载缓存（一般是<code>gcc-arm-none-eabi-7-2018-q2-update-win32</code>编译器，Windows环境下载巨慢,实验室仓库已存）。</li><li><strong>driver/</strong>：底层驱动抽象（ADC/SPI/I2C/TIM/PWM、Flash、DRV83xx/栅极驱动、放大器、保护等）。</li><li><strong>encoder/</strong>：霍尔、ABI/AS504x/MT6816 等编码器支持。</li><li><strong>hwconf/</strong>：<strong>板级硬件配置核心</strong>：GPIO/ADC 索引、分压比、NTC 参数、DRV830x 引脚与寄存器、PWM 定时器通道映射等。给新板适配基本都在这改。</li><li><strong>imu/</strong>：IMU 传感器（MPU/ICM 等）与姿态算法。</li><li><strong>libcanard/</strong>：UAVCAN 轻量协议栈（需要 CAN 上做 UAVCAN 时用）。</li><li><strong>lispBM/</strong>：内嵌 Lisp 虚拟机（在 VESC 上跑脚本）。</li><li><strong>make/</strong>：构建规则、链接脚本、MCU/晶振等编译选项。</li><li><strong>motor/</strong>：电机控制算法（FOC、观测器、SVPWM、速度/位置环、限流/限压）。</li><li><strong>Project/</strong>：IDE 工程/示例（例如 Eclipse 工程）。</li><li><strong>qmlui/</strong>：QML 小界面/示例 UI（部分板/屏幕用）。</li><li><strong>tests/</strong>：单元/回归测试与仿真桩。</li><li><strong>tools/</strong>：打包、烧录、生成版本号等脚本。</li><li><strong>util/</strong>：通用工具（滤波、数学库、PID、CRC、NTC 计算等）。</li><li>根目录的 <strong>bms.c / bms.h</strong>：与电池管理相关的模块入口（某些板会用）。</li><li><strong>.gdbinit / .gitignore / .travis.yml</strong>：调试、忽略与 CI 配置。</li></ul>',11)])])}const C=t(n,[["render",s]]);export{m as __pageData,C as default};
